from urllib.parse import urlparse

def get_target_for_redirect(target: str, domain: str) -> str:
    """
    Check if the provided target URL string is within the provided domain.
    If so, return the target URL for redirect (forced to https); otherwise,
    fallback to the domain URL for redirect.
    """
    try:
        parsed = urlparse(target)
    except Exception:
        return f"https://{domain}"

    # Only allow http or https schemes
    if parsed.scheme not in ("http", "https"):
        return f"https://{domain}"

    host = parsed.hostname
    if host is None:
        return f"https://{domain}"

    # Normalize host and domain (lowercase, strip trailing dot)
    host = host.rstrip(".")
    domain_norm = domain.rstrip(".")

    if host == domain_norm or host.endswith("." + domain_norm):
        # Force https scheme while preserving other components
        secured = parsed._replace(scheme="https")
        return secured.geturl()
    else:
        return f"https://{domain_norm}"

