from typing import List

def _file_mode_string(mode: int) -> str:
    """Convert a file's mode to a string like '-rw-r--r--'."""
    is_dir = 'd' if stat.S_ISDIR(mode) else '-'
    perms = []
    for who in ('USR', 'GRP', 'OTH'):
        for perm in ('R', 'W', 'X'):
            if mode & getattr(stat, f'S_I{perm}{who}'):
                perms.append(perm.lower())
            else:
                perms.append('-')
    return is_dir + ''.join(perms)

def _get_ls_l_entry(path: str, entry_name: str) -> str:
    """Return a single line resembling `ls -l` for the given entry."""
    try:
        st = os.stat(os.path.join(path, entry_name))
    except OSError:
        return ''
    mode_str = _file_mode_string(st.st_mode)
    nlink = st.st_nlink
    try:
        owner = pwd.getpwuid(st.st_uid).pw_name
    except KeyError:
        owner = str(st.st_uid)
    try:
        group = grp.getgrgid(st.st_gid).gr_name
    except KeyError:
        group = str(st.st_gid)
    size = st.st_size
    mtime = time.localtime(st.st_mtime)
    # Format: Mon DD HH:MM or Mon DD  YYYY (if year differs)
    now = time.time()
    six_months_ago = now - (6 * 30 * 24 * 3600)
    if st.st_mtime < six_months_ago or st.st_mtime > now + (6 * 30 * 24 * 3600):
        time_str = time.strftime('%b %d  %Y', mtime)
    else:
        time_str = time.strftime('%b %d %H:%M', mtime)
    return f'{mode_str} {nlink:>2} {owner:<8} {group:<8} {size:>8} {time_str} {entry_name}'

def get_ls_result(dir_path: str) -> str:
    if not isinstance(dir_path, str) or not dir_path:
        return ''
    if not os.path.isdir(dir_path):
        return ''
    try:
        entries: List[str] = sorted(os.listdir(dir_path))
    except OSError:
        return ''
    lines = []
    for name in entries:
        line = _get_ls_l_entry(dir_path, name)
        if line:
            lines.append(line)
    # Mimic ls -l output: each entry on its own line, plus a trailing newline
    return '\n'.join(lines) + ('\n' if lines else '')

import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.
    '''
    _bin_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Pow: operator.pow,
    }
    _unary_ops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval_node(node):
        if isinstance(node, ast.Expression):
            return _eval_node(node.body)
        elif isinstance(node, ast.BinOp):
            left = _eval_node(node.left)
            right = _eval_node(node.right)
            op_type = type(node.op)
            if op_type in _bin_ops:
                return _bin_ops[op_type](left, right)
            raise ValueError(f'Unsupported binary operator: {op_type}')
        elif isinstance(node, ast.UnaryOp):
            operand = _eval_node(node.operand)
            op_type = type(node.op)
            if op_type in _unary_ops:
                return _unary_ops[op_type](operand)
            raise ValueError(f'Unsupported unary operator: {op_type}')
        elif isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError('Non-numeric constant')
        elif hasattr(ast, 'Num') and isinstance(node, ast.Num):
            return node.n
        raise ValueError(f'Unsupported expression element: {type(node).__name__}')

    try:
        tree = ast.parse(expr, mode='eval')
        result = _eval_node(tree)
        return str(result)
    except Exception:
        return ''

from typing import Dict

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    mapping = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control',
    }
    if info_type not in mapping:
        return header
    if any(ch in info_content for ch in ('\n', '\r')):
        return header
    new_header = header.copy()
    new_header[mapping[info_type]] = info_content
    return new_header

