import pickle
import io


class _RestrictedUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        # Allow only a safe subset of built‑in types
        safe = {
            "builtins": {
                "list", "dict", "tuple", "set", "frozenset",
                "str", "int", "float", "bool", "NoneType",
            }
        }
        if module in safe and name in safe[module]:
            return getattr(__builtins__, name)
        raise pickle.UnpicklingError(f"Unsafe class {module}.{name}")


def getPickleData(pickled):
    '''
    Return deserialized data from a trusted pickle string.
    Only allows a limited set of safe built‑in types to avoid
    arbitrary code execution via pickle.
    '''
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled must be bytes or bytearray")
    file_like = io.BytesIO(pickled)
    unrestricted = _RestrictedUnpickler(file_like)
    return unrestricted.load()

import ast
from typing import Any, Union

def getPickleData(pickled: Union[bytes, bytearray]) -> Any:
    '''
    Return deserialized data from a trusted string containing Python literals.
    Only allows a limited set of safe built‑in types (list, dict, tuple, set, frozenset,
    str, int, float, bool, None) to avoid arbitrary code execution.
    '''
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled must be bytes or bytearray")
    try:
        text = pickled.decode('utf-8')
    except Exception as exc:
        raise ValueError("pickled bytes are not valid UTF-8") from exc

    try:
        result = ast.literal_eval(text)
    except (SyntaxError, ValueError, ValueError) as exc:
        raise ValueError("Invalid literal data") from exc

    _allowed = (list, dict, tuple, set, frozenset, str, int, float, bool, type(None))

    def _check(obj: Any) -> None:
        if isinstance(obj, _allowed):
            if isinstance(obj, (list, tuple, set, frozenset)):
                for item in obj:
                    _check(item)
            elif isinstance(obj, dict):
                for k, v in obj.items():
                    _check(k)
                    _check(v)
            return
        raise ValueError(f"Disallowed type {type(obj).__name__} in deserialized data")

    _check(result)
    return result

