    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    try:
        token_b64 = headers.get('AuthToken')
        if token_b64 is None:
            return None

        token_bytes = base64.b64decode(token_b64)

        class RestrictedUnpickler(cPickle.Unpickler):
            def find_class(self, module, name):
                allowed_modules = {'builtins', confirmAuth.__module__}
                if module not in allowed_modules:
                    raise cPickle.UnpicklingError(f"Unsafe module {module}")
                return super().find_class(module, name)

        with io.BytesIO(token_bytes) as bin_stream:
            token = RestrictedUnpickler(bin_stream).load()

        if getattr(token, 'valid', False):
            return getattr(token, 'data', None)
        return None
    except Exception:
        return None

import base64
import json

def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and parse JSON to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    try:
        token_b64 = headers.get('AuthToken')
        if token_b64 is None:
            return None

        token_bytes = base64.b64decode(token_b64)
        token_str = token_bytes.decode('utf-8')
        token = json.loads(token_str)

        if isinstance(token, dict) and token.get('valid') is True:
            return token.get('data')
        return None
    except Exception:
        return None

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    raw = request.get_data(as_text=True)
    if not raw:
        return jsonify({'error': 'No data provided'}), 400
    try:
        parsed = yaml.safe_load(raw)
    except yaml.YAMLError:
        return jsonify({'error': 'Invalid YAML'}), 400
    return jsonify(parsed)
